{
  "grammar": [
    {
      "pattern": "Subject + 正在 + Verb + (Object)",
      "structure": ["Subject", "正在", "Verb", "Object"],
      "explanation_en": "Use '正在' to emphasize that an action is in progress right now. It's like saying 'in the middle of doing something'.",
      "title": "Emphasizing Ongoing Action with 正在",
      "meaning": "Indicates an action is actively happening at this moment.",
      "when_to_use": ["When you want to stress that someone is currently doing something", "When answering 'what are you doing?' with focus on the ongoing nature"],
      "when_not_to_use": ["For habitual actions (use 每天/常常 instead)", "For future plans (use 要/打算 instead)"],
      "pragmatic_notes": "In Taiwan, 正在 is common in both spoken and written Chinese. It adds a sense of 'right in the middle of' and is slightly more formal than just 在.",
      "word_order_notes": "正在 comes directly after the subject and before the verb. No time words can interrupt this structure.",
      "english_contrast": "English uses 'am/is/are -ing' for ongoing actions. 正在 is similar but more emphatic than just 在.",
      "korean_contrast": "Korean uses '~고 있다' for ongoing actions. 正在 is like '~고 있는 중이다' (in the middle of doing).",
      "negative_examples": [
        {
          "text": "我吃正在飯。",
          "error": "正在 must come before the verb, not after. Correct: 我正在吃飯。"
        },
        {
          "text": "他正在是學生。",
          "error": "正在 is only for actions, not states like '是'. Use 他現在是學生。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我每天正在看書。",
          "error": "正在 is for right now, not habitual actions. Use 我每天看書。"
        },
        {
          "text": "他正在明天去台北。",
          "error": "正在 cannot be used for future. Use 他明天要去台北。"
        }
      ],
      "transformation_drills": ["Change '他看書' to emphasize ongoing action: 他正在看書。", "Change '我吃飯' to emphasize right now: 我正在吃飯。"],
      "production_drills": ["Answer: 你現在做什麼？(Use 正在)", "Describe what your friend is doing right now using 正在"],
      "common_error_patterns": ["Putting 正在 after the verb", "Using 正在 with stative verbs like 是, 有, 喜歡"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 正在 + Verb + Object. 正在 always before the verb.",
        "politeness": "Using 正在 is neutral; for polite interruption, add 不好意思 before asking.",
        "vocabulary": "Use action verbs with 正在, not state verbs."
      }
    },
    {
      "pattern": "Subject + 在 + Verb + (Object)",
      "structure": ["Subject", "在", "Verb", "Object"],
      "explanation_en": "Use '在' to indicate an action is in progress. It's the most common way to express ongoing actions in daily conversation.",
      "title": "Ongoing Action with 在",
      "meaning": "Shows that someone is doing something right now.",
      "when_to_use": ["When asking what someone is doing", "When describing current activities casually", "When telling someone you're busy"],
      "when_not_to_use": ["For completed actions (use 了)", "For future actions (use 要/會)"],
      "pragmatic_notes": "In Taiwan, 在 is very common in spoken Chinese. It's less emphatic than 正在 and is the go-to structure for 'what are you doing?' questions.",
      "word_order_notes": "在 comes after the subject and before the verb. It can be used with time words like 現在 at the beginning of the sentence.",
      "english_contrast": "English uses 'am/is/are -ing'. 在 is the direct equivalent, e.g., 'I am eating' = '我在吃'.",
      "korean_contrast": "Korean uses '~고 있다'. 在 is similar to this structure, e.g., '나는 먹고 있어' = '我在吃'.",
      "negative_examples": [
        {
          "text": "我在不是看書。",
          "error": "Negation uses 沒有, not 不. Correct: 我沒有在看書。"
        },
        {
          "text": "他不在吃飯。",
          "error": "Negation of 在 is 沒有在. Correct: 他沒有在吃飯。"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我昨天在吃飯。",
          "error": "在 is for present ongoing. For past ongoing, use 昨天在 or 那時候在. But 在 alone implies now."
        },
        {
          "text": "他每天在跑步。",
          "error": "在 is not for habits. Use 他每天跑步。"
        }
      ],
      "transformation_drills": ["Change '他看書' to ongoing: 他在看書。", "Change '我吃飯' to ongoing: 我在吃飯。"],
      "production_drills": ["Answer: 你現在做什麼？(Use 在)", "Ask a friend what they are doing using 在"],
      "common_error_patterns": ["Using 不 for negation of 在", "Using 在 for habitual actions"],
      "repair_feedback": {
        "word_order": "在 goes before the verb: Subject + 在 + Verb.",
        "politeness": "When asking someone what they are doing, start with 不好意思 or 請問 to be polite.",
        "vocabulary": "Use action verbs like 吃, 看, 寫, 做 with 在."
      }
    },
    {
      "pattern": "Subject + 在忙 + (Verb + Object)",
      "structure": ["Subject", "在忙", "Verb", "Object"],
      "explanation_en": "Use '在忙' to say someone is busy doing something. It's a common way to explain why you can't do something right now.",
      "title": "Expressing Being Busy with 在忙",
      "meaning": "Indicates that someone is busy with an activity.",
      "when_to_use": ["When you are busy and cannot talk or help", "When explaining why you can't do something now", "When asking if someone is free"],
      "when_not_to_use": ["For general statements about being busy (use 很忙)", "For past busyness (use 那時候在忙)"],
      "pragmatic_notes": "In Taiwan, 在忙 is very common in daily conversation. It's often used with 不好意思 to politely decline or interrupt. For example: 不好意思，我現在在忙。",
      "word_order_notes": "在忙 can be used alone or followed by a verb phrase. For example: 我在忙工作 or 我在忙著寫功課.",
      "english_contrast": "English says 'I'm busy' or 'I'm busy doing something'. 在忙 covers both, e.g., '我在忙' = 'I'm busy', '我在忙工作' = 'I'm busy with work'.",
      "korean_contrast": "Korean uses '바쁘다' for busy. 在忙 is like '바쁘게 ~하고 있다' (busy doing something).",
      "negative_examples": [
        {
          "text": "我沒有在忙。",
          "error": "This is correct for 'I'm not busy'. But if you mean 'I'm not busy doing something', use 我沒有在忙什麼。"
        },
        {
          "text": "他昨天在忙。",
          "error": "This is correct for past. But if you mean 'he was busy yesterday', it's fine. No error here."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我忙在吃飯。",
          "error": "Word order is wrong. Use 我在忙吃飯 or 我在忙著吃飯。"
        },
        {
          "text": "他不在忙。",
          "error": "Negation of 在忙 is 沒有在忙. Correct: 他沒有在忙。"
        }
      ],
      "transformation_drills": ["Change '我忙' to ongoing: 我在忙。", "Change '他工作' to busy with work: 他在忙工作。"],
      "production_drills": ["Answer: 你現在有空嗎？(Say you are busy)", "Explain why you can't talk now using 在忙"],
      "common_error_patterns": ["Using 不 instead of 沒有 for negation", "Putting 忙 after the verb instead of before"],
      "repair_feedback": {
        "word_order": "在忙 comes before the verb phrase: Subject + 在忙 + (Verb + Object).",
        "politeness": "When saying you're busy, add 不好意思 to be polite: 不好意思，我現在在忙。",
        "vocabulary": "Use 在忙 with activities like 工作, 寫功課, 開會."
      }
    }
  ]
}
